styling:
#io-wrapper { position: relative; display: inline-block; }
#io-overlay { position: absolute; top: 0; left: 0; width: 100%; height: 100%; }
#io-overlay svg { width: 100%; height: 100%; }
#io-original img { max-width: 100%; display: block; }
#io-header { font-size: 1.1em; font-weight: bold; margin-bottom: 0.5em; }
#io-footer, #io-remarks, #io-sources, #io-extra-1, #io-extra-2 { margin-top: 0.5em; font-size: 0.9em; }
.card { font-family: arial; font-size: 20px; text-align: center; color: black; background-color: white; }
.io-mask-question { fill: var(--inactive-shape-color, #ffeba2); stroke: var(--inactive-shape-border-color, #212121); stroke-width: 1px; }
.io-mask-answer { fill: var(--active-shape-color, #ff8e8e); stroke: var(--active-shape-border-color, #212121); stroke-width: 1px; }
